const createTrashService = (authenticatedFetch) => ({
  async fetchTrashFiles() {
    const response = await authenticatedFetch("/trash");
    const data = await response.json();

    if (!response.ok) {
      throw new Error(data.message || "Failed to load trash files.");
    }

    return data.files || [];
  },

  async restoreFile(fileId) {
    const response = await authenticatedFetch("/restore", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({ fileId })
    });
    const data = await response.json();

    if (!response.ok) {
      throw new Error(data.message || "Failed to restore file.");
    }

    return data;
  },

  async permanentlyDeleteFile(fileId) {
    const response = await authenticatedFetch("/delete", {
      method: "DELETE",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        fileId,
        permanent: true
      })
    });
    const data = await response.json();

    if (!response.ok) {
      throw new Error(data.message || "Failed to permanently delete file.");
    }

    return data;
  }
});

export default createTrashService;
